export async function apiPostForm(url: string, form: FormData, token?: string) {
  const res = await fetch(url, {
    method: 'POST',
    headers: token ? { Authorization: `Bearer ${token}` } : undefined,
    body: form,
  });
  if (!res.ok) {
    throw new Error(`POST form failed: ${res.status}`);
  }
  return res.json();
}
